import * as React from 'react'
import { styled } from 'styled-components'
import { FaDownload, FaInstagram, FaLinkedin, FaGithub } from 'react-icons/fa'
import Portrait from '../images/portrait.png'
import Cv from '../files/Resume.pdf'

const PageContainer = styled.div`
    width: 100%;
    height: 100%;
    display: grid;
    place-items: center;
    background-color: crimson;
`

const HeroContainer = styled.div`
    width: 100%;
    display: flex;
    flex-direction: column;
    row-gap: 0;
    text-align: center;

    @media (min-width: 768px) {
        flex-direction: row;
        max-width: 1200px;
    }
`

const HeroImage = styled.img`
    width: 100%;
    mask: linear-gradient(black, 95%, transparent);
`

const HeroMain = styled.div`
    display: flex;
    flex-direction: column;
    row-gap: 1rem;
    padding: 0 1rem;
`

const HeroText = styled.div`
    text-align: left;

    & h1 {
        margin: 0;
        font-family: 'Rock Salt', cursive;
    }

    & p {
        margin: 0;
    }
`

const LinkContainer = styled.div`
    display: flex;
    justify-content: space-between;
`

const DownloadButton = styled.button`
    border: 3px solid maroon;
    border-right: none;
    border-radius: 1.5rem;
    padding: 0.5rem 0;
    background-color: transparent;
    color: white;
    font-size: 1rem;
    cursor: pointer;

    &:hover, &:hover i {
        border-color: white;
    }

    & span {
        padding: 0 0.75rem;
    }

    & i {
        border: 3px solid maroon;
        border-radius: 1.5rem;
        padding: 0.5rem 0.75rem;
    }
`

const SocialLinks = styled.div`
    display: flex;
    column-gap: 2rem;
`

const FontAwesomeIcon = styled.a`
    font-size: 2.5rem;
    text-decoration: none;
    color: maroon;

    &:hover {
        color: white;
    }
`

const IndexPage = () => {
    const downloadResume = () => {
        const anchor = document.createElement('a')
        anchor.href = Cv;
        anchor.download = 'Curtis Caulfield Resume.pdf'
        anchor.target = '_blank'
        anchor.click()
    }

    return (
        <PageContainer>
            <HeroContainer>
                <div>
                    <HeroImage src={Portrait} />
                </div>
                <HeroMain>
                    <HeroText>
                        <h1>Hey, my name is Curtis.</h1>
                        <p>
                            An undergraduate, currently studying a Masters degree in Software Engineering, Curtis is
                            relentlessly ambitious, and driven by the desire to succeed. To this extent, he has earned
                            multiple awards for the best performance in his year, and knows that the best is still
                            yet to come.
                        </p>
                    </HeroText>
                    <LinkContainer>
                        <div>
                            <DownloadButton
                                onClick={downloadResume}>
                                <span>Download CV</span>
                                <i><FaDownload /></i>
                            </DownloadButton>
                        </div>
                        <SocialLinks>
                            <FontAwesomeIcon
                                href="https://www.instagram.com/curtiscaulfield/"
                                target="_blank"
                                title="Instagram">
                                    <FaInstagram />
                            </FontAwesomeIcon>
                            <FontAwesomeIcon
                                href="https://www.linkedin.com/in/curtiscaulfield/"
                                target="_blank"
                                title="LinkedIn">
                                    <FaLinkedin />
                            </FontAwesomeIcon>
                            <FontAwesomeIcon
                                href="https://github.com/codedbycurtis"
                                target="_blank"
                                title="GitHub">
                                    <FaGithub />
                            </FontAwesomeIcon>
                        </SocialLinks>
                    </LinkContainer>
                </HeroMain>
            </HeroContainer>
        </PageContainer>
    )
}

export default IndexPage

export const Head = () => <title>Curtis Caulfield</title>